import { Router, Request, Response } from 'express';
import { db } from '../database';
import { authenticateToken, requireAdmin } from './auth';

const router = Router();

// 获取所有商品（带分页、搜索、筛选、排序）
router.get('/', (req: Request, res: Response) => {
  try {
    const {
      page = '1',
      limit = '20',
      search = '',
      category = '',
      sort = 'created_at',
      order = 'DESC',
      min_price,
      max_price,
      in_stock,
    } = req.query;

    const pageNum = Math.max(1, parseInt(page as string, 10) || 1);
    const limitNum = Math.min(100, Math.max(1, parseInt(limit as string, 10) || 20));
    const offset = (pageNum - 1) * limitNum;

    const conditions: string[] = ['p.is_deleted = 0'];
    const params: any[] = [];

    if (search) {
      conditions.push('(p.name LIKE ? OR p.description LIKE ?)');
      params.push(`%${search}%`, `%${search}%`);
    }

    if (category) {
      conditions.push('p.category = ?');
      params.push(category);
    }

    if (min_price) {
      conditions.push('p.price >= ?');
      params.push(parseFloat(min_price as string));
    }

    if (max_price) {
      conditions.push('p.price <= ?');
      params.push(parseFloat(max_price as string));
    }

    if (in_stock === 'true') {
      conditions.push('p.stock > 0');
    }

    const allowedSortFields = ['price', 'name', 'stock', 'sales', 'created_at', 'rating'];
    const sortField = allowedSortFields.includes(sort as string) ? sort : 'created_at';
    const sortOrder = (order as string).toUpperCase() === 'ASC' ? 'ASC' : 'DESC';

    const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';

    const countResult = db.prepare(
      `SELECT COUNT(*) as total FROM products p ${whereClause}`
    ).get(...params) as any;

    const total = countResult.total;
    const totalPages = Math.ceil(total / limitNum);

    const products = db.prepare(
      `SELECT p.*, 
        COALESCE(AVG(r.rating), 0) as avg_rating,
        COUNT(DISTINCT r.id) as review_count
      FROM products p
      LEFT JOIN reviews r ON p.id = r.product_id
      ${whereClause}
      GROUP BY p.id
      ORDER BY p.${sortField} ${sortOrder}
      LIMIT ? OFFSET ?`
    ).run(...params, limitNum, offset);

    // SQLite doesn't return rows directly with .run(), use .all() instead
    const productsList = db.prepare(
      `SELECT p.*, 
        COALESCE(AVG(r.rating), 0) as avg_rating,
        COUNT(DISTINCT r.id) as review_count
      FROM products p
      LEFT JOIN reviews r ON p.id = r.product_id
      ${whereClause}
      GROUP BY p.id
      ORDER BY p.${sortField} ${sortOrder}
      LIMIT ? OFFSET ?`
    ).all(...params, limitNum, offset);

    res.json({
      products: productsList,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total,
        totalPages,
        hasMore: pageNum < totalPages,
      },
    });
  } catch (error) {
    console.error('获取商品列表失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

// 获取商品分类列表
router.get('/categories', (_req: Request, res: Response) => {
  try {
    const categories = db.prepare(
      'SELECT DISTINCT category FROM products WHERE is_deleted = 0 ORDER BY category'
    ).all();

    res.json({ categories: (categories as any[]).map((c: any) => c.category) });
  } catch (error) {
    console.error('获取分类失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

// 获取单个商品详情
router.get('/:id', (req: Request, res: Response) => {
  try {
    const { id } = req.params;

    const product = db.prepare(
      `SELECT p.*, 
        COALESCE(AVG(r.rating), 0) as avg_rating,
        COUNT(DISTINCT r.id) as review_count
      FROM products p
      LEFT JOIN reviews r ON p.id = r.product_id
      WHERE p.id = ? AND p.is_deleted = 0
      GROUP BY p.id`
    ).get(id) as any;

    if (!product) {
      res.status(404).json({ error: '商品不存在' });
      return;
    }

    // 获取商品评价
    const reviews = db.prepare(
      `SELECT r.*, u.username, u.avatar as user_avatar
       FROM reviews r
       JOIN users u ON r.user_id = u.id
       WHERE r.product_id = ?
       ORDER BY r.created_at DESC
       LIMIT 10`
    ).all(id);

    // 更新浏览次数
    db.prepare('UPDATE products SET views = views + 1 WHERE id = ?').run(id);

    res.json({
      product,
      reviews,
    });
  } catch (error) {
    console.error('获取商品详情失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

// 创建商品（管理员）
router.post('/', authenticateToken, requireAdmin, (req: Request, res: Response) => {
  try {
    const {
      name,
      description,
      price,
      stock,
      category,
      image_url,
      images,
      specifications,
    } = req.body;

    if (!name || !price) {
      res.status(400).json({ error: '商品名称和价格为必填项' });
      return;
    }

    if (typeof price !== 'number' || price <= 0) {
      res.status(400).json({ error: '价格必须为正数' });
      return;
    }

    if (stock !== undefined && (typeof stock !== 'number' || stock < 0)) {
      res.status(400).json({ error: '库存不能为负数' });
      return;
    }

    const now = new Date().toISOString();

    const result = db.prepare(
      `INSERT INTO products (name, description, price, stock, category, image_url, images, specifications, created_at, updated_at)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
    ).run(
      name,
      description || '',
      price,
      stock ?? 0,
      category || '未分类',
      image_url || '',
      images ? JSON.stringify(images) : '[]',
      specifications ? JSON.stringify(specifications) : '{}',
      now,
      now
    );

    const product = db.prepare('SELECT * FROM products WHERE id = ?').get(result.lastInsertRowid);

    res.status(201).json({
      message: '商品创建成功',
      product,
    });
  } catch (error) {
    console.error('创建商品失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

// 更新商品（管理员）
router.put('/:id', authenticateToken, requireAdmin, (req: Request, res: Response) => {
  try {
    const { id } = req.params;
    const {
      name,
      description,
      price,
      stock,
      category,
      image_url,
      images,
      specifications,
      is_active,
    } = req.body;

    const existing = db.prepare('SELECT * FROM products WHERE id = ? AND is_deleted = 0').get(id) as any;
    if (!existing) {
      res.status(404).json({ error: '商品不存在' });
      return;
    }

    const updates: string[] = [];
    const values: any[] = [];

    if (name !== undefined) { updates.push('name = ?'); values.push(name); }
    if (description !== undefined) { updates.push('description = ?'); values.push(description); }
    if (price !== undefined) {
      if (typeof price !== 'number' || price <= 0) {
        res.status(400).json({ error: '价格必须为正数' });
        return;
      }
      updates.push('price = ?');
      values.push(price);
    }
    if (stock !== undefined) {
      if (typeof stock !== 'number' || stock < 0) {
        res.status(400).json({ error: '库存不能为负数' });
        return;
      }
      updates.push('stock = ?');
      values.push(stock);
    }
    if (category !== undefined) { updates.push('category = ?'); values.push(category); }
    if (image_url !== undefined) { updates.push('image_url = ?'); values.push(image_url); }
    if (images !== undefined) { updates.push('images = ?'); values.push(JSON.stringify(images)); }
    if (specifications !== undefined) { updates.push('specifications = ?'); values.push(JSON.stringify(specifications)); }
    if (is_active !== undefined) { updates.push('is_active = ?'); values.push(is_active ? 1 : 0); }

    if (updates.length === 0) {
      res.status(400).json({ error: '没有需要更新的字段' });
      return;
    }

    updates.push('updated_at = ?');
    values.push(new Date().toISOString());
    values.push(id);

    db.prepare(`UPDATE products SET ${updates.join(', ')} WHERE id = ?`).run(...values);

    const updated = db.prepare('SELECT * FROM products WHERE id = ?').get(id);

    res.json({ message: '商品更新成功', product: updated });
  } catch (error) {
    console.error('更新商品失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

// 删除商品（管理员，软删除）
router.delete('/:id', authenticateToken, requireAdmin, (req: Request, res: Response) => {
  try {
    const { id } = req.params;

    const existing = db.prepare('SELECT * FROM products WHERE id = ? AND is_deleted = 0').get(id) as any;
    if (!existing) {
      res.status(404).json({ error: '商品不存在' });
      return;
    }

    db.prepare('UPDATE products SET is_deleted = 1, updated_at = ? WHERE id = ?')
      .run(new Date().toISOString(), id);

    res.json({ message: '商品已删除' });
  } catch (error) {
    console.error('删除商品失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

// 添加商品评价
router.post('/:id/reviews', authenticateToken, (req: Request, res: Response) => {
  try {
    const { id: productId } = req.params;
    const userId = (req as any).user.userId;
    const { rating, content } = req.body;

    const product = db.prepare('SELECT id FROM products WHERE id = ? AND is_deleted = 0').get(productId) as any;
    if (!product) {
      res.status(404).json({ error: '商品不存在' });
      return;
    }

    if (!rating || rating < 1 || rating > 5) {
      res.status(400).json({ error: '评分必须在1-5之间' });
      return;
    }

    // 检查是否已评价
    const existingReview = db.prepare(
      'SELECT id FROM reviews WHERE user_id = ? AND product_id = ?'
    ).get(userId, productId) as any;

    if (existingReview) {
      res.status(409).json({ error: '您已评价过该商品' });
      return;
    }

    const now = new Date().toISOString();
    db.prepare(
      'INSERT INTO reviews (user_id, product_id, rating, content, created_at) VALUES (?, ?, ?, ?, ?)'
    ).run(userId, productId, rating, content || '', now);

    // 更新商品评分
    const avgResult = db.prepare(
      'SELECT AVG(rating) as avg_rating FROM reviews WHERE product_id = ?'
    ).get(productId) as any;

    db.prepare('UPDATE products SET rating = ?, updated_at = ? WHERE id = ?')
      .run(Math.round(avgResult.avg_rating * 10) / 10, now, productId);

    res.status(201).json({ message: '评价成功' });
  } catch (error) {
    console.error('添加评价失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

// 获取热门商品
router.get('/featured/hot', (req: Request, res: Response) => {
  try {
    const limit = Math.min(20, parseInt(req.query.limit as string, 10) || 10);

    const products = db.prepare(
      `SELECT p.*, COALESCE(AVG(r.rating), 0) as avg_rating
       FROM products p
       LEFT JOIN reviews r ON p.id = r.product_id
       WHERE p.is_deleted = 0 AND p.is_active = 1
       GROUP BY p.id
       ORDER BY p.sales DESC, p.views DESC
       LIMIT ?`
    ).all(limit);

    res.json({ products });
  } catch (error) {
    console.error('获取热门商品失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

export default router;

import { Router, Request, Response } from 'express';
import { db } from '../database';
import { authenticateToken } from './auth';

const router = Router();

// 所有购物车路由需要认证
router.use(authenticateToken);

// 获取购物车
router.get('/', (req: Request, res: Response) => {
  try {
    const userId = (req as any).user.userId;

    const cartItems = db.prepare(
      `SELECT c.id as cart_id, c.quantity, c.created_at as added_at,
              p.id as product_id, p.name, p.price, p.image_url, p.stock, p.is_active, p.is_deleted
       FROM cart c
       JOIN products p ON c.product_id = p.id
       WHERE c.user_id = ?
       ORDER BY c.created_at DESC`
    ).all(userId) as any[];

    // 过滤无效商品并计算总价
    const validItems = cartItems.filter(
      (item) => !item.is_deleted && item.is_active
    );

    const items = validItems.map((item) => ({
      id: item.cart_id,
      product_id: item.product_id,
      name: item.name,
      price: item.price,
      image_url: item.image_url,
      quantity: item.quantity,
      stock: item.stock,
      subtotal: item.price * item.quantity,
      added_at: item.added_at,
    }));

    const totalAmount = items.reduce((sum, item) => sum + item.subtotal, 0);
    const totalItems = items.reduce((sum, item) => sum + item.quantity, 0);

    res.json({
      items,
      summary: {
        totalItems,
        totalAmount: Math.round(totalAmount * 100) / 100,
      },
    });
  } catch (error) {
    console.error('获取购物车失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

// 添加商品到购物车
router.post('/add', (req: Request, res: Response) => {
  try {
    const userId = (req as any).user.userId;
    const { product_id, quantity = 1 } = req.body;

    if (!product_id) {
      res.status(400).json({ error: '商品ID为必填项' });
      return;
    }

    if (typeof quantity !== 'number' || quantity < 1) {
      res.status(400).json({ error: '数量必须为正整数' });
      return;
    }

    // 检查商品是否存在且有效
    const product = db.prepare(
      'SELECT id, stock, is_active, is_deleted FROM products WHERE id = ?'
    ).get(product_id) as any;

    if (!product || product.is_deleted) {
      res.status(404).json({ error: '商品不存在' });
      return;
    }

    if (!product.is_active) {
      res.status(400).json({ error: '商品已下架' });
      return;
    }

    // 检查购物车中是否已有该商品
    const existingCartItem = db.prepare(
      'SELECT id, quantity FROM cart WHERE user_id = ? AND product_id = ?'
    ).get(userId, product_id) as any;

    if (existingCartItem) {
      const newQuantity = existingCartItem.quantity + quantity;

      if (newQuantity > product.stock) {
        res.status(400).json({
          error: `库存不足，当前库存: ${product.stock}，购物车已有: ${existingCartItem.quantity}`,
        });
        return;
      }

      db.prepare('UPDATE cart SET quantity = ?, updated_at = ? WHERE id = ?')
        .run(newQuantity, new Date().toISOString(), existingCartItem.id);

      res.json({
        message: '购物车已更新',
        cart_id: existingCartItem.id,
        quantity: newQuantity,
      });
    } else {
      if (quantity > product.stock) {
        res.status(400).json({
          error: `库存不足，当前库存: ${product.stock}`,
        });
        return;
      }

      const now = new Date().toISOString();
      const result = db.prepare(
        'INSERT INTO cart (user_id, product_id, quantity, created_at, updated_at) VALUES (?, ?, ?, ?, ?)'
      ).run(userId, product_id, quantity, now, now);

      res.status(201).json({
        message: '已添加到购物车',
        cart_id: result.lastInsertRowid,
        quantity,
      });
    }
  } catch (error) {
    console.error('添加购物车失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

