router.put('/item/:cartId', (req: Request, res: Response) => {
  try {
    const userId = (req as any).user.userId;
    const { cartId } = req.params;
    const { quantity } = req.body;

    if (quantity === undefined || typeof quantity !== 'number' || quantity < 0) {
      res.status(400).json({ error: '数量必须为非负整数' });
      return;
    }

    const cartItem = db.prepare(
      `SELECT c.id, c.product_id, p.stock, p.is_active, p.is_deleted
       FROM cart c
       JOIN products p ON c.product_id = p.id
       WHERE c.id = ? AND c.user_id = ?`
    ).get(cartId, userId) as any;

    if (!cartItem) {
      res.status(404).json({ error: '购物车商品不存在' });
      return;
    }

    if (cartItem.is_deleted || !cartItem.is_active) {
      res.status(400).json({ error: '商品已失效' });
      return;
    }

    if (quantity === 0) {
      // 数量为0则移除
      db.prepare('DELETE FROM cart WHERE id = ? AND user_id = ?').run(cartId, userId);
      res.json({ message: '商品已从购物车移除' });
      return;
    }

    if (quantity > cartItem.stock) {
      res.status(400).json({
        error: `库存不足，当前库存: ${cartItem.stock}`,
      });
      return;
    }

    db.prepare('UPDATE cart SET quantity = ?, updated_at = ? WHERE id = ? AND user_id = ?')
      .run(quantity, new Date().toISOString(), cartId, userId);

    res.json({ message: '数量已更新', quantity });
  } catch (error) {
    console.error('更新购物车失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

