import { Router, Request, Response } from 'express';
import { db } from '../database';
import { authenticateToken, requireAdmin } from './auth';

const router = Router();

// 所有订单路由需要认证
router.use(authenticateToken);

// 生成订单号
function generateOrderNo(): string {
  const now = new Date();
  const dateStr = now.toISOString().slice(0, 10).replace(/-/g, '');
  const timeStr = now.toTimeString().slice(0, 8).replace(/:/g, '');
  const random = Math.random().toString(36).substring(2, 8).toUpperCase();
  return `ORD${dateStr}${timeStr}${random}`;
}

// 创建订单（从购物车结算）
router.post('/', (req: Request, res: Response) => {
  try {
    const userId = (req as any).user.userId;
    const {
      cart_ids,       // 指定购物车商品ID结算
      address_id,     // 收货地址ID
      remark,         // 订单备注
      payment_method = 'online', // 支付方式
    } = req.body;

    // 获取要结算的购物车商品
    let cartItems: any[];
    if (Array.isArray(cart_ids) && cart_ids.length > 0) {
      const placeholders = cart_ids.map(() => '?').join(',');
      cartItems = db.prepare(
        `SELECT c.id as cart_id, c.quantity, p.id as product_id, p.name, p.price, p.image_url, p.stock, p.is_active, p.is_deleted
         FROM cart c
         JOIN products p ON c.product_id = p.id
         WHERE c.user_id = ? AND c.id IN (${placeholders})`
      ).all(userId, ...cart_ids) as any[];
    } else {
      // 默认结算所有选中的商品，如无选中则结算全部
      cartItems = db.prepare(
        `SELECT c.id as cart_id, c.quantity, p.id as product_id, p.name, p.price, p.image_url, p.stock, p.is_active, p.is_deleted
         FROM cart c
         JOIN products p ON c.product_id = p.id
         WHERE c.user_id = ? AND c.is_selected = 1`
      ).all(userId) as any[];

      if (cartItems.length === 0) {
        cartItems = db.prepare(
          `SELECT c.id as cart_id, c.quantity, p.id as product_id, p.name, p.price, p.image_url, p.stock, p.is_active, p.is_deleted
           FROM cart c
           JOIN products p ON c.product_id = p.id
           WHERE c.user_id = ?`
        ).all(userId) as any[];
      }
    }

    if (cartItems.length === 0) {
      res.status(400).json({ error: '购物车为空，无法创建订单' });
      return;
    }

    // 验证所有商品
    for (const item of cartItems) {
      if (item.is_deleted || !item.is_active) {
        res.status(400).json({
          error: `商品「${item.name}」已失效，请从购物车移除`,
        });
        return;
      }
      if (item.quantity > item.stock) {
        res.status(400).json({
          error: `商品「${item.name}」库存不足，当前库存: ${item.stock}`,
        });
        return;
      }
    }

    // 获取收货地址
    let shippingAddress: any = null;
    if (address_id) {
      shippingAddress = db.prepare(
        'SELECT * FROM addresses WHERE id = ? AND user_id = ?'
      ).get(address_id, userId) as any;
    } else {
      shippingAddress = db.prepare(
        'SELECT * FROM addresses WHERE user_id = ? AND is_default = 1'
      ).get(userId) as any;
    }

    if (!shippingAddress) {
      res.status(400).json({ error: '请先添加收货地址' });
      return;
    }

    const now = new Date().toISOString();
    const orderNo = generateOrderNo();

    // 计算金额
    const itemsTotal = cartItems.reduce(
      (sum, item) => sum + item.price * item.quantity, 0
    );
    const shippingFee = itemsTotal >= 99 ? 0 : 8; // 满99包邮
    const totalAmount = itemsTotal + shippingFee;

    // 使用事务创建订单
    const createOrder = db.transaction(() => {
      // 插入订单
      const orderResult = db.prepare(
        `INSERT INTO orders (order_no, user_id, status, total_amount, shipping_fee, 
         payment_method, shipping_name, shipping_phone, shipping_address, 
         shipping_city, shipping_district, shipping_zip, remark, created_at, updated_at)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
      ).run(
        orderNo,
        userId,
        'pending', // pending, paid, shipped, delivered, completed, cancelled
        totalAmount,
        shippingFee,
        payment_method,
        shippingAddress.recipient_name || shippingAddress.name,
        shippingAddress.phone,
        shippingAddress.address,
        shippingAddress.city || '',
        shippingAddress.district || '',
        shippingAddress.zip_code || '',
        remark || '',
        now,
        now
      );

      const orderId = orderResult.lastInsertRowid;

      // 插入订单商品明细 & 扣减库存 & 增加销量
      const insertItem = db.prepare(
        `INSERT INTO order_items (order_id, product_id, product_name, product_image, price, quantity, subtotal)
         VALUES (?, ?, ?, ?, ?, ?, ?)`
      );

      const updateStock = db.prepare(
        'UPDATE products SET stock = stock - ?, sales = sales + ?, updated_at = ? WHERE id = ?'
      );

      for (const item of cartItems) {
        const subtotal = item.price * item.quantity;
        insertItem.run(
          orderId,
          item.product_id,
          item.name,
          item.image_url || '',
          item.price,
          item.quantity,
          subtotal
        );
        updateStock.run(item.quantity, item.quantity, now, item.product_id);
      }

      // 清除已结算的购物车商品
      const cartIdsToRemove = cartItems.map((i: any) => i.cart_id);
      const placeholders = cartIdsToRemove.map(() => '?').join(',');
      db.prepare(
        `DELETE FROM cart WHERE user_id = ? AND id IN (${placeholders})`
      ).run(userId, ...cartIdsToRemove);

      return orderId;
    });

    const orderId = createOrder();

    // 获取完整订单信息
    const order = db.prepare('SELECT * FROM orders WHERE id = ?').get(orderId);
    const items = db.prepare('SELECT * FROM order_items WHERE order_id = ?').all(orderId);

    res.status(201).json({
      message: '订单创建成功',
      order: {
        ...order as any,
        items,
      },
    });
  } catch (error) {
    console.error('创建订单失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

// 获取用户订单列表
router.get('/', (req: Request, res: Response) => {
  try {
    const userId = (req as any).user.userId;
    const {
      page = '1',
      limit = '10',
      status = '',
      sort = 'created_at',
      order = 'DESC',
    } = req.query;

    const pageNum = Math.max(1, parseInt(page as string, 10) || 1);
    const limitNum = Math.min(50, Math.max(1, parseInt(limit as string, 10) || 10));
    const offset = (pageNum - 1) * limitNum;

    const conditions: string[] = ['o.user_id = ?'];
    const params: any[] = [userId];

    if (status) {
      conditions.push('o.status = ?');
      params.push(status);
    }

    const whereClause = `WHERE ${conditions.join(' AND ')}`;

    const allowedSortFields = ['created_at', 'total_amount', 'status'];
    const sortField = allowedSortFields.includes(sort as string) ? sort : 'created_at';
    const sortOrder = (order as string).toUpperCase() === 'ASC' ? 'ASC' : 'DESC';

    const countResult = db.prepare(
      `SELECT COUNT(*) as total FROM orders o ${whereClause}`
    ).get(...params) as any;

    const total = countResult.total;
    const totalPages = Math.ceil(total / limitNum);

    const orders = db.prepare(
      `SELECT o.* FROM orders o ${whereClause}
       ORDER BY o.${sortField} ${sortOrder}
       LIMIT ? OFFSET ?`
    ).all(...params, limitNum, offset) as any[];

    // 获取每个订单的商品数量
    const ordersWithItemCount = orders.map((order) => {
      const countResult = db.prepare(
        'SELECT COUNT(*) as count FROM order_items WHERE order_id = ?'
      ).get(order.id) as any;

      return {
        ...order,
        item_count: countResult.count,
      };
    });

    res.json({
      orders: ordersWithItemCount,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total,
        totalPages,
        hasMore: pageNum < totalPages,
      },
    });
  } catch (error) {
    console.error('获取订单列表失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

