// 取消订单
router.put('/:id/cancel', (req: Request, res: Response) => {
  try {
    const userId = (req as any).user.userId;
    const { id } = req.params;
    const { reason } = req.body;

    const order = db.prepare(
      'SELECT * FROM orders WHERE id = ? AND user_id = ?'
    ).get(id, userId) as any;

    if (!order) {
      res.status(404).json({ error: '订单不存在' });
      return;
    }

    const cancelableStatuses = ['pending', 'paid'];
    if (!cancelableStatuses.includes(order.status)) {
      res.status(400).json({
        error: `订单状态为「${order.status}」，无法取消`,
      });
      return;
    }

    const now = new Date().toISOString();

    // 使用事务：取消订单 + 恢复库存
    const cancelOrder = db.transaction(() => {
      db.prepare(
        'UPDATE orders SET status = ?, cancel_reason = ?, updated_at = ? WHERE id = ?'
      ).run('cancelled', reason || '', now, id);

      // 恢复库存
      const items = db.prepare('SELECT product_id, quantity FROM order_items WHERE order_id = ?').all(id) as any[];
      for (const item of items) {
        db.prepare('UPDATE products SET stock = stock + ?, sales = sales - ?, updated_at = ? WHERE id = ?')
          .run(item.quantity, item.quantity, now, item.product_id);
      }
    });

    cancelOrder();

    res.json({ message: '订单已取消' });
  } catch (error) {
    console.error('取消订单失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

