router.put('/:id/status', requireAdmin, (req: Request, res: Response) => {
  try {
    const { id } = req.params;
    const { status, tracking_number, tracking_company } = req.body;

    const validStatuses = ['pending', 'paid', 'shipped', 'delivered', 'completed', 'cancelled'];
    if (!validStatuses.includes(status)) {
      res.status(400).json({ error: '无效的订单状态' });
      return;
    }

    const order = db.prepare('SELECT * FROM orders WHERE id = ?').get(id) as any;
    if (!order) {
      res.status(404).json({ error: '订单不存在' });
      return;
    }

    const now = new Date().toISOString();
    const updates: string[] = ['status = ?', 'updated_at = ?'];
    const values: any[] = [status, now];

    // 根据状态更新对应时间字段
    if (status === 'paid' && !order.paid_at) {
      updates.push('paid_at = ?');
      values.push(now);
    }
    if (status === 'shipped') {
      updates.push('shipped_at = ?');
      values.push(now);
    }
    if (status === 'delivered') {
      updates.push('delivered_at = ?');
      values.push(now);
    }
    if (status === 'completed' && !order.received_at) {
      updates.push('received_at = ?');
      values.push(now);
    }

    if (tracking_number) {
      updates.push('tracking_number = ?');
      values.push(tracking_number);
    }
    if (tracking_company) {
      updates.push('tracking_company = ?');
      values.push(tracking_company);
    }

    values.push(id);

    db.prepare(`UPDATE orders SET ${updates.join(', ')} WHERE id = ?`).run(...values);

    res.json({ message: '订单状态已更新' });
  } catch (error) {
    console.error('更新订单状态失败:', error);
    res.status(500).json({ error: '服务器内部错误' });
  }
});

