    const totalOrders = db.prepare('SELECT COUNT(*) as count FROM orders').get() as any;
    const pendingOrders = db.prepare(
      "SELECT COUNT(*) as count FROM orders WHERE status = 'pending'"
    ).get() as any;
    const todayOrders = db.prepare(
      "SELECT COUNT(*) as count FROM orders WHERE DATE(created_at) = ?"
    ).get(today) as any;
    const totalRevenue = db.prepare(
      "SELECT COALESCE(SUM(total_amount), 0) as total FROM orders WHERE status IN ('paid', 'shipped', 'delivered', 'completed')"
    ).get() as any;
    const todayRevenue = db.prepare(
      "SELECT COALESCE(SUM(total_amount), 0) as total FROM orders WHERE DATE(created_at) = ? AND status IN ('paid', 'shipped', 'delivered', 'completed')"
    ).get(today) as any;

    // 各状态订单数量
    const statusCounts = db.prepare(
      'SELECT status, COUNT(*) as count FROM orders GROUP BY status'
    ).all() as any[];

