            <span className="mx-2">/</span>
            <span className="text-gray-700">{product.name}</span>
          </div>
        </div>
      </div>

      {/* Product Detail */}
      <div className="container mx-auto px-4 py-8">
        <div className="bg-white rounded-2xl shadow-sm overflow-hidden">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 p-8">
            {/* Images */}
            <div className="space-y-4">
              <div className="aspect-square bg-gray-100 rounded-xl overflow-hidden">
                <img
                  src={images[activeImage]}
                  alt={product.name}
                  className="w-full h-full object-cover"
                />
              </div>
              {images.length > 1 && (
                <div className="flex space-x-3">
                  {images.map((image, index) => (
                    <button
                      key={index}
                      onClick={() => setActiveImage(index)}
                      className={`w-20 h-20 rounded-lg overflow-hidden border-2 transition ${
                        activeImage === index ? 'border-indigo-600' : 'border-transparent'
                      }`}
                    >
                      <img src={image} alt="" className="w-full h-full object-cover" />
                    </button>
                  ))}
                </div>
              )}
            </div>

            {/* Info */}
            <div className="space-y-6">
              <div>
                <span className="inline-block px-3 py-1 bg-indigo-100 text-indigo-700 text-sm rounded-full mb-3">
                  {product.category}
                </span>
                <h1 className="text-2xl font-bold text-gray-800 mb-2">{product.name}</h1>
                <p className="text-gray-500">{product.description}</p>
              </div>

              {/* Price */}
              <div className="bg-gray-50 rounded-xl p-4">
                <div className="flex items-baseline">
                  <span className="text-3xl font-bold text-red-500">
                    {formatPrice(product.price)}
                  </span>
                  {product.originalPrice && (
                    <>
                      <span className="text-lg text-gray-400 line-through ml-3">
                        {formatPrice(product.originalPrice)}
                      </span>
                      <span className="ml-2 px-2 py-0.5 bg-red-100 text-red-600 text-sm rounded">
                        限时优惠
                      </span>
                    </>
                  )}
                </div>
                {product.discount && (
                  <div className="mt-2 text-sm text-gray-500">
                    节省 {formatPrice(product.originalPrice! - product.price)}
                  </div>
                )}
              </div>

              {/* Stats */}
              <div className="flex items-center space-x-6 text-sm">
                <div className="flex items-center">
                  <span className="text-gray-500 mr-2">评分:</span>
                  <div className="flex">{renderStars(4.5)}</div>
                  <span className="ml-1 text-gray-600">(128条评价)</span>
                </div>
                <div className="text-gray-500">
                  销量: <span className="text-gray-700">{product.sales || 0}</span>
                </div>
              </div>

              {/* Stock */}
              <div className="flex items-center">
                <span className="text-gray-500 mr-2">库存:</span>
                {product.stock > 0 ? (
                  <span className="text-green-600">
                    {product.stock < 10 ? `仅剩 ${product.stock} 件` : '有货'}
                  </span>
                ) : (
                  <span className="text-red-600">缺货</span>
                )}
              </div>

              {/* Quantity */}
              {product.stock > 0 && (
                <div>
                  <span className="text-gray-500 mr-4">数量:</span>
                  <div className="inline-flex items-center">
                    <button
                      onClick={() => handleQuantityChange(-1)}
                      disabled={quantity <= 1}
                      className="w-10 h-10 border border-gray-300 rounded-l-lg hover:bg-gray-100 disabled:opacity-50"
                    >
                      -
                    </button>
                    <input
                      type="number"
                      value={quantity}
                      onChange={(e) => setQuantity(Math.max(1, Math.min(product.stock, parseInt(e.target.value) || 1)))}
                      className="w-16 h-10 border-y border-gray-300 text-center focus:outline-none"
                    />
                    <button
                      onClick={() => handleQuantityChange(1)}
                      disabled={quantity >= product.stock}
                      className="w-10 h-10 border border-gray-300 rounded-r-lg hover:bg-gray-100 disabled:opacity-50"
                    >
                      +
                    </button>
                  </div>
                </div>
              )}

              {/* Actions */}
              <div className="flex space-x-4">
                <button
                  onClick={handleAddToCart}
                  disabled={product.stock <= 0 || addingToCart}
                  className={`flex-1 py-3 rounded-lg font-semibold transition ${
                    product.stock <= 0
                      ? 'bg-gray-100 text-gray-400 cursor-not-allowed'
                      : addingToCart
                      ? 'bg-indigo-400 text-white cursor-not-allowed'
                      : 'bg-indigo-600 text-white hover:bg-indigo-700'
                  }`}
                >
                  {product.stock <= 0 ? '缺货' : addingToCart ? '添加中...' : '加入购物车'}
                </button>
                <button
                  onClick={handleBuyNow}
                  disabled={product.stock <= 0 || addingToCart}
                  className={`flex-1 py-3 rounded-lg font-semibold transition ${
                    product.stock <= 0
                      ? 'bg-gray-100 text-gray-400 cursor-not-allowed'
                      : addingToCart
                      ? 'bg-red-400 text-white cursor-not-allowed'
                      : 'bg-red-500 text-white hover:bg-red-600'
                  }`}
                >
                  立即购买
                </button>
                <button
                  onClick={handleAddToWishlist}
                  disabled={addingToWishlist}
                  className="w-12 h-12 border border-gray-300 rounded-lg hover:bg-gray-50 flex items-center justify-center transition"
                >
                  <svg className="w-6 h-6 text-gray-400 hover:text-red-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
                  </svg>
                </button>
              </div>

              {/* Service */}
              <div className="grid grid-cols-2 gap-4 pt-4 border-t">
                <div className="flex items-center text-sm text-gray-500">
                  <svg className="w-5 h-5 mr-2 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                  </svg>
                  7天无理由退换
                </div>
                <div className="flex items-center text-sm text-gray-500">
                  <svg className="w-5 h-5 mr-2 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                  </svg>
                  正品保证
                </div>
                <div className="flex items-center text-sm text-gray-500">
                  <svg className="w-5 h-5 mr-2 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                  </svg>
                  急速发货
                </div>
                <div className="flex items-center text-sm text-gray-500">
                  <svg className="w-5 h-5 mr-2 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                  </svg>
                  售后无忧
                </div>
              </div>
            </div>
          </div>

          {/* Tabs */}
          <div className="border-t">
            <div className="flex border-b">
              <button
                onClick={() => setActiveTab('description')}
                className={`px-8 py-4 font-medium transition ${
                  activeTab === 'description'
                    ? 'text-indigo-600 border-b-2 border-indigo-600'
                    : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                商品详情
              </button>
              <button
                onClick={() => setActiveTab('reviews')}
                className={`px-8 py-4 font-medium transition ${
                  activeTab === 'reviews'
                    ? 'text-indigo-600 border-b-2 border-indigo-600'
                    : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                商品评价 ({reviews.length})
              </button>
            </div>

            <div className="p-8">
              {activeTab === 'description' ? (
                <div className="prose max-w-none">
                  <h3 className="text-lg font-semibold mb-4">商品描述</h3>
                  <p className="text-gray-600 whitespace-pre-line">{product.description}</p>

                  {product.specifications && (
                    <>
                      <h3 className="text-lg font-semibold mt-8 mb-4">规格参数</h3>
                      <table className="w-full border-collapse">
                        <tbody>
                          {Object.entries(product.specifications).map(([key, value]) => (
                            <tr key={key} className="border-b">
                              <td className="py-3 pr-4 text-gray-500">{key}</td>
                              <td className="py-3">{value}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </>
                  )}
                </div>
              ) : (
                <div className="space-y-6">
                  {/* Rating Summary */}
                  <div className="flex items-center space-x-8 p-6 bg-gray-50 rounded-xl">
                    <div className="text-center">
                      <div className="text-4xl font-bold text-gray-800">4.5</div>
                      <div className="flex justify-center my-2">{renderStars(4)}</div>
                      <div className="text-sm text-gray-500">128条评价</div>
                    </div>
                    <div className="flex-1">
                      <div className="flex items-center mb-2">
                        <span className="text-sm text-gray-600 w-12">5星</span>
                        <div className="flex-1 h-2 bg-gray-200 rounded-full mx-2">
                          <div className="h-2 bg-yellow-400 rounded-full" style={{ width: '80%' }}></div>
                        </div>
                        <span className="text-sm text-gray-500">80%</span>
                      </div>
