export default ProductDetail;

import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { cartService, orderService, CartItem } from '../services/api';

const Cart: React.FC = () => {
  const navigate = useNavigate();
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
  const [updatingId, setUpdatingId] = useState<number | null>(null);
  const [removingId, setRemovingId] = useState<number | null>(null);
  const [processing, setProcessing] = useState(false);

  useEffect(() => {
    loadCart();
  }, []);

  const loadCart = async () => {
    try {
      setLoading(true);
      const data = await cartService.getCart();
      setCartItems(data.items || []);
      // Select all items by default
      setSelectedItems(new Set(data.items.map(item => item.id)));
    } catch (error) {
      console.error('Failed to load cart:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSelectAll = () => {
    if (selectedItems.size === cartItems.length) {
      setSelectedItems(new Set());
    } else {
      setSelectedItems(new Set(cartItems.map(item => item.id)));
    }
  };

  const handleSelectItem = (id: number) => {
    const newSelected = new Set(selectedItems);
    if (newSelected.has(id)) {
      newSelected.delete(id);
    } else {
      newSelected.add(id);
    }
    setSelectedItems(newSelected);
  };

  const handleUpdateQuantity = async (id: number, quantity: number) => {
    if (quantity < 1) return;

    try {
      setUpdatingId(id);
      await cartService.updateItem(id, quantity);
      setCartItems(prev =>
        prev.map(item =>
          item.id === id ? { ...item, quantity } : item
        )
      );
    } catch (error) {
      console.error('Failed to update quantity:', error);
      alert('更新失败，请重试');
    } finally {
      setUpdatingId(null);
    }
  };

  const handleRemoveItem = async (id: number) => {
    if (!confirm('确定要从购物车移除此商品？')) return;

    try {
      setRemovingId(id);
      await cartService.removeItem(id);
      setCartItems(prev => prev.filter(item => item.id !== id));
      setSelectedItems(prev => {
        const newSelected = new Set(prev);
        newSelected.delete(id);
        return newSelected;
      });
    } catch (error) {
      console.error('Failed to remove item:', error);
      alert('移除失败，请重试');
    } finally {
      setRemovingId(null);
    }
  };

  const handleClearCart = async () => {
    if (!confirm('确定要清空购物车？')) return;

    try {
      await cartService.clearCart();
      setCartItems([]);
      setSelectedItems(new Set());
    } catch (error) {
      console.error('Failed to clear cart:', error);
      alert('清空失败，请重试');
    }
  };

  const handleCheckout = async () => {
    if (selectedItems.size === 0) {
      alert('请选择要结算的商品');
      return;
    }

    try {
      setProcessing(true);

      // Create order with selected items
      const selectedCartItems = cartItems.filter(item => selectedItems.has(item.id));
      const orderData = {
        items: selectedCartItems.map(item => ({
          productId: item.productId,
          quantity: item.quantity,
          price: item.price
        })),
        totalAmount: subtotal,
        shippingAddress: '默认地址', // In real app, this would be selected from user's addresses
        contactPhone: '13800138000'
      };

      const order = await orderService.createOrder(orderData);
      navigate(`/orders/${order.id}`);
    } catch (error) {
      console.error('Failed to checkout:', error);
      alert('结算失败，请重试');
    } finally {
      setProcessing(false);
    }
  };

  const subtotal = cartItems
    .filter(item => selectedItems.has(item.id))
    .reduce((sum, item) => sum + item.price * item.quantity, 0);

  const totalItems = cartItems.reduce((sum, item) => sum + item.quantity, 0);
  const totalSelectedItems = cartItems
    .filter(item => selectedItems.has(item.id))
    .reduce((sum, item) => sum + item.quantity, 0);

  const formatPrice = (price: number): string => {
    return new Intl.NumberFormat('zh-CN', {
      style: 'currency',
      currency: 'CNY'
    }).format(price);
  };

  if (loading) {
    return (
