                            className="w-12 h-8 border-y border-gray-300 text-center focus:outline-none"
                          />
                          <button
                            onClick={() => handleUpdateQuantity(item.id, item.quantity + 1)}
                            disabled={updatingId === item.id || item.quantity >= item.stock}
