                  <div className="border-t pt-3 flex justify-between font-semibold">
                    <span className="text-gray-800">合计</span>
                    <span className="text-xl text-red-500">{formatPrice(subtotal + (subtotal >= 99 ? 0 : 10))}</span>
                  </div>
                </div>

                <button
