};

export default Cart;

import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { orderService, Order } from '../services/api';

type OrderStatus = 'all' | 'pending' | 'paid' | 'shipped' | 'delivered' | 'cancelled';

const OrderList: React.FC = () => {
  const navigate = useNavigate();
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState<OrderStatus>('all');
  const [currentPage, setCurrentPage] = useState(1);

  const ordersPerPage = 10;

  useEffect(() => {
    loadOrders();
  }, []);

  const loadOrders = async () => {
    try {
      setLoading(true);
      const data = await orderService.getOrders();
      setOrders(data);
    } catch (error) {
      console.error('Failed to load orders:', error);
    } finally {
      setLoading(false);
    }
  };

  const filteredOrders = orders.filter(order => {
    if (statusFilter === 'all') return true;
    return order.status === statusFilter;
  });

  const totalPages = Math.ceil(filteredOrders.length / ordersPerPage);
  const paginatedOrders = filteredOrders.slice(
    (currentPage - 1) * ordersPerPage,
    currentPage * ordersPerPage
  );

  const getStatusLabel = (status: string): { text: string; color: string; bg: string } => {
    const statusMap: Record<string, { text: string; color: string; bg: string }> = {
      pending: { text: '待付款', color: 'text-orange-600', bg: 'bg-orange-100' },
      paid: { text: '已付款', color: 'text-blue-600', bg: 'bg-blue-100' },
      shipped: { text: '配送中', color: 'text-purple-600', bg: 'bg-purple-100' },
      delivered: { text: '已完成', color: 'text-green-600', bg: 'bg-green-100' },
      cancelled: { text: '已取消', color: 'text-gray-600', bg: 'bg-gray-100' }
    };
    return statusMap[status] || { text: status, color: 'text-gray-600', bg: 'bg-gray-100' };
  };

  const formatPrice = (price: number): string => {
    return new Intl.NumberFormat('zh-CN', {
      style: 'currency',
      currency: 'CNY'
    }).format(price);
  };

  const formatDate = (dateString: string): string => {
    return new Date(dateString).toLocaleDateString('zh-CN', {
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const handleCancelOrder = async (orderId: number) => {
    if (!confirm('确定要取消此订单吗？')) return;

    try {
      await orderService.cancelOrder(orderId);
      setOrders(prev =>
        prev.map(order =>
          order.id === orderId ? { ...order, status: 'cancelled' } : order
        )
      );
      alert('订单已取消');
    } catch (error) {
      console.error('Failed to cancel order:', error);
      alert('取消失败，请重试');
    }
  };

  const handlePayOrder = async (orderId: number) => {
    try {
      await orderService.payOrder(orderId);
      setOrders(prev =>
        prev.map(order =>
          order.id === orderId ? { ...order, status: 'paid' } : order
        )
      );
      alert('支付成功');
    } catch (error) {
      console.error('Failed to pay order:', error);
      alert('支付失败，请重试');
    }
  };

  const handleReceiveOrder = async (orderId: number) => {
    if (!confirm('确认已收到货物吗？')) return;

    try {
      await orderService.receiveOrder(orderId);
      setOrders(prev =>
        prev.map(order =>
          order.id === orderId ? { ...order, status: 'delivered' } : order
        )
      );
      alert('确认收货成功');
    } catch (error) {
      console.error('Failed to receive order:', error);
      alert('操作失败，请重试');
    }
  };

  const statusCounts = {
    all: orders.length,
    pending: orders.filter(o => o.status === 'pending').length,
    paid: orders.filter(o => o.status === 'paid').length,
    shipped: orders.filter(o => o.status === 'shipped').length,
    delivered: orders.filter(o => o.status === 'delivered').length,
    cancelled: orders.filter(o => o.status === 'cancelled').length
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-white shadow-sm">
        <div className="container mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <Link to="/" className="text-2xl font-bold text-indigo-600">
              电商平台
            </Link>
            <nav className="flex items-center space-x-6">
              <Link to="/products" className="text-gray-600 hover:text-indigo-600 transition">
                商品列表
              </Link>
              <Link to="/cart" className="text-gray-600 hover:text-indigo-600 transition flex items-center">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z" />
                </svg>
              </Link>
              <Link to="/login" className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition">
                登录
              </Link>
            </nav>
          </div>
        </div>
      </header>

      <div className="container mx-auto px-4 py-8">
        <h1 className="text-2xl font-bold text-gray-800 mb-8">我的订单</h1>

        {/* Status Tabs */}
        <div className="bg-white rounded-xl shadow-sm mb-6 overflow-hidden">
          <div className="flex overflow-x-auto">
            {[
              { key: 'all' as OrderStatus, label: '全部订单' },
              { key: 'pending' as OrderStatus, label: '待付款' },
              { key: 'paid' as OrderStatus, label: '已付款' },
              { key: 'shipped' as OrderStatus, label: '配送中' },
              { key: 'delivered' as OrderStatus, label: '已完成' },
              { key: 'cancelled' as OrderStatus, label: '已取消' }
            ].map(tab => (
              <button
                key={tab.key}
                onClick={() => {
                  setStatusFilter(tab.key);
                  setCurrentPage(1);
                }}
                className={`px-6 py-4 font-medium whitespace-nowrap transition ${
                  statusFilter === tab.key
                    ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50'
                    : 'text-gray-600 hover:text-indigo-600 hover:bg-gray-50'
                }`}
              >
                {tab.label}
                {statusCounts[tab.key] > 0 && (
                  <span className={`ml-2 px-2 py-0.5 rounded-full text-xs ${
                    statusFilter === tab.key ? 'bg-indigo-600 text-white' : 'bg-gray-200 text-gray-600'
                  }`}>
                    {statusCounts[tab.key]}
                  </span>
                )}
              </button>
            ))}
          </div>
        </div>

        {/* Orders */}
        {loading ? (
          <div className="space-y-4">
            {[...Array(3)].map((_, i) => (
              <div key={i} className="bg-white rounded-xl shadow-sm p-6">
                <div className="h-6 bg-gray-200 rounded animate-pulse mb-4 w-1/4"></div>
                <div className="flex space-x-4">
                  <div className="w-20 h-20 bg-gray-200 rounded animate-pulse"></div>
                  <div className="flex-1 space-y-2">
                    <div className="h-4 bg-gray-200 rounded animate-pulse w-3/4"></div>
                    <div className="h-4 bg-gray-200 rounded animate-pulse w-1/2"></div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : paginatedOrders.length === 0 ? (
          <div className="bg-white rounded-xl shadow-sm p-12 text-center">
            <svg className="w-24 h-24 text-gray-300 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" />
            </svg>
            <h2 className="text-xl font-semibold text-gray-800 mb-2">暂无订单</h2>
            <p className="text-gray-500 mb-6">快去挑选心仪的商品吧！</p>
            <Link
              to="/products"
              className="inline-block px-6 py-3 bg-indigo-600 text-white rounded-lg font-semibold hover:bg-indigo-700 transition"
            >
              去购物
            </Link>
          </div>
        ) : (
          <>
            <div className="space-y-4">
              {paginatedOrders.map(order => {
                const statusInfo = getStatusLabel(order.status);
                return (
                  <div key={order.id} className="bg-white rounded-xl shadow-sm overflow-hidden">
                    {/* Order Header */}
                    <div className="flex items-center justify-between px-6 py-4 border-b bg-gray-50">
                      <div className="flex items-center space-x-4 text-sm text-gray-500">
                        <span>订单号: {order.orderNumber}</span>
                        <span>|</span>
                        <span>{formatDate(order.createdAt)}</span>
                      </div>
                      <span className={`px-3 py-1 rounded-full text-sm font-medium ${statusInfo.color} ${statusInfo.bg}`}>
                        {statusInfo.text}
                      </span>
                    </div>

                    {/* Order Items */}
                    <div className="p-6">
                      <div className="space-y-4">
                        {order.items.map((item, index) => (
                          <div key={index} className="flex items-center">
                            <Link to={`/products/${item.productId}`} className="flex-shrink-0">
                              <img
                                src={item.image || 'https://via.placeholder.com/80'}
                                alt={item.name}
                                className="w-20 h-20 object-cover rounded-lg"
                              />
                            </Link>
                            <div className="ml-4 flex-1">
                              <Link
                                to={`/products/${item.productId}`}
                                className="font-medium text-gray-800 hover:text-indigo-600"
                              >
                                {item.name}
                              </Link>
                              {item.variant && (
                                <p className="text-sm text-gray-500 mt-1">{item.variant}</p>
