import { useState } from 'react';
import { Link } from 'react-router-dom';

export interface Product {
  id: string | number;
  name: string;
  description: string;
  price: number;
  originalPrice?: number;
  image: string;
  rating: number;
  reviewCount: number;
  category: string;
  inStock: boolean;
  stockCount?: number;
  tags?: string[];
}

interface ProductCardProps {
  product: Product;
  onAddToCart?: (product: Product) => void;
  onAddToWishlist?: (product: Product) => void;
  onQuickView?: (product: Product) => void;
  isInWishlist?: boolean;
  isLoading?: boolean;
}

export default function ProductCard({
  product,
  onAddToCart,
  onAddToWishlist,
  onQuickView,
  isInWishlist = false,
  isLoading = false,
}: ProductCardProps) {
  const [imageLoaded, setImageLoaded] = useState(false);
  const [imageError, setImageError] = useState(false);
  const [isHovered, setIsHovered] = useState(false);

  const discountPercentage = product.originalPrice
    ? Math.round(((product.originalPrice - product.price) / product.originalPrice) * 100)
    : 0;

  const handleAddToCart = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (onAddToCart && product.inStock) {
      onAddToCart(product);
    }
  };

  const handleAddToWishlist = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (onAddToWishlist) {
      onAddToWishlist(product);
    }
  };

  const handleQuickView = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (onQuickView) {
      onQuickView(product);
    }
  };

  const renderStars = (rating: number) => {
    const stars = [];
    const fullStars = Math.floor(rating);
    const hasHalfStar = rating % 1 >= 0.5;

    for (let i = 0; i < fullStars; i++) {
      stars.push(
        <svg
          key={`full-${i}`}
          className="w-4 h-4 text-yellow-400 fill-current"
          viewBox="0 0 20 20"
        >
          <path d="M10 15l-5.878 3.09 1.123-6.545L.489 6.91l6.572-.955L10 0l2.939 5.955 6.572.955-4.756 4.635 1.123 6.545z" />
        </svg>
      );
    }

    if (hasHalfStar) {
      stars.push(
        <svg
          key="half"
          className="w-4 h-4 text-yellow-400 fill-current"
          viewBox="0 0 20 20"
        >
          <defs>
            <linearGradient id="halfGradient">
              <stop offset="50%" stopColor="currentColor" />
              <stop offset="50%" stopColor="#d1d5db" />
            </linearGradient>
          </defs>
          <path
            fill="url(#halfGradient)"
            d="M10 15l-5.878 3.09 1.123-6.545L.489 6.91l6.572-.955L10 0l2.939 5.955 6.572.955-4.756 4.635 1.123 6.545z"
          />
        </svg>
      );
    }

    const emptyStars = 5 - stars.length;
    for (let i = 0; i < emptyStars; i++) {
      stars.push(
        <svg
          key={`empty-${i}`}
          className="w-4 h-4 text-gray-300 fill-current"
          viewBox="0 0 20 20"
        >
          <path d="M10 15l-5.878 3.09 1.123-6.545L.489 6.91l6.572-.955L10 0l2.939 5.955 6.572.955-4.756 4.635 1.123 6.545z" />
        </svg>
      );
    }

    return stars;
  };

  return (
    <div
      className={`group relative bg-white rounded-xl shadow-sm hover:shadow-xl transition-all duration-300 overflow-hidden ${
        isLoading ? 'animate-pulse' : ''
      }`}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <Link to={`/product/${product.id}`}>
        {/* Image Container */}
        <div className="relative aspect-square overflow-hidden bg-gray-100">
          {!imageLoaded && !imageError && (
            <div className="absolute inset-0 bg-gray-200 animate-pulse" />
          )}
          {imageError ? (
            <div className="absolute inset-0 flex items-center justify-center bg-gray-200">
              <svg
                className="w-12 h-12 text-gray-400"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"
                />
              </svg>
            </div>
          ) : (
            <img
              src={product.image}
              alt={product.name}
              className={`w-full h-full object-cover transition-transform duration-500 ${
                isHovered ? 'scale-110' : 'scale-100'
              } ${imageLoaded ? 'opacity-100' : 'opacity-0'}`}
              onLoad={() => setImageLoaded(true)}
              onError={() => setImageError(true)}
            />
          )}

          {/* Badges */}
          <div className="absolute top-3 left-3 flex flex-col gap-2">
            {discountPercentage > 0 && (
              <span className="px-2 py-1 bg-red-500 text-white text-xs font-bold rounded-md">
                -{discountPercentage}%
              </span>
            )}
            {product.tags?.includes('new') && (
              <span className="px-2 py-1 bg-green-500 text-white text-xs font-bold rounded-md">
                NEW
              </span>
            )}
            {product.tags?.includes('bestseller') && (
              <span className="px-2 py-1 bg-orange-500 text-white text-xs font-bold rounded-md">
                BESTSELLER
              </span>
            )}
          </div>

          {/* Wishlist Button */}
          <button
            onClick={handleAddToWishlist}
            className={`absolute top-3 right-3 p-2 rounded-full transition-all duration-300 ${
              isInWishlist
                ? 'bg-red-500 text-white'
                : 'bg-white/90 text-gray-600 hover:bg-red-500 hover:text-white'
            } shadow-md`}
            aria-label={isInWishlist ? 'Remove from wishlist' : 'Add to wishlist'}
          >
            <svg
              className="w-5 h-5"
              fill={isInWishlist ? 'currentColor' : 'none'}
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"
              />
            </svg>
          </button>

          {/* Quick Actions Overlay */}
          <div
            className={`absolute inset-x-0 bottom-0 bg-gradient-to-t from-black/70 to-transparent p-4 transition-all duration-300 ${
              isHovered ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'
            }`}
          >
            <div className="flex gap-2">
              <button
                onClick={handleQuickView}
                className="flex-1 py-2 bg-white text-gray-800 rounded-lg font-medium hover:bg-gray-100 transition-colors"
              >
                Quick View
              </button>
              <button
                onClick={handleAddToCart}
                disabled={!product.inStock}
                className={`flex-1 py-2 rounded-lg font-medium transition-colors ${
                  product.inStock
                    ? 'bg-blue-600 text-white hover:bg-blue-700'
                    : 'bg-gray-400 text-white cursor-not-allowed'
                }`}
              >
                {product.inStock ? 'Add to Cart' : 'Out of Stock'}
              </button>
            </div>
          </div>
        </div>

        {/* Product Info */}
        <div className="p-4">
          <p className="text-xs text-blue-600 font-medium uppercase tracking-wide mb-1">
            {product.category}
          </p>
          <h3 className="text-gray-800 font-semibold text-lg mb-2 line-clamp-2 group-hover:text-blue-600 transition-colors">
            {product.name}
          </h3>
          <p className="text-gray-500 text-sm mb-3 line-clamp-2">
            {product.description}
          </p>

          {/* Rating */}
          <div className="flex items-center gap-2 mb-3">
            <div className="flex">{renderStars(product.rating)}</div>
            <span className="text-sm text-gray-500">
              ({product.reviewCount} reviews)
            </span>
          </div>

          {/* Price */}
          <div className="flex items-center gap-2">
            <span className="text-xl font-bold text-gray-900">
              ${product.price.toFixed(2)}
            </span>
            {product.originalPrice && (
              <span className="text-sm text-gray-400 line-through">
                ${product.originalPrice.toFixed(2)}
              </span>
            )}
          </div>

          {/* Stock Status */}
          {product.stockCount !== undefined && product.stockCount <= 5 && product.stockCount > 0 && (
            <p className="text-xs text-orange-500 mt-2 font-medium">
              Only {product.stockCount} left in stock
            </p>
          )}
        </div>
      </Link>
    </div>
  );
}

import { useState } from 'react';

export interface CartItem {
  id: string | number;
  productId: string | number;
  name: string;
  price: number;
  quantity: number;
  image: string;
  maxQuantity?: number;
  selected?: boolean;
}

interface CartItemProps {
  item: CartItem;
  onUpdateQuantity?: (itemId: string | number, quantity: number) => void;
  onRemove?: (itemId: string | number) => void;
  onToggleSelect?: (itemId: string | number, selected: boolean) => void;
  onSaveForLater?: (item: CartItem) => void;
  isLoading?: boolean;
  readOnly?: boolean;
}

export default function CartItem({
  item,
  onUpdateQuantity,
  onRemove,
  onToggleSelect,
  onSaveForLater,
  isLoading = false,
  readOnly = false,
}: CartItemProps) {
  const [isRemoving, setIsRemoving] = useState(false);
  const [imageLoaded, setImageLoaded] = useState(false);
  const [imageError, setImageError] = useState(false);

  const maxQuantity = item.maxQuantity || 99;
  const isMaxQuantity = item.quantity >= maxQuantity;
  const isMinQuantity = item.quantity <= 1;

  const handleQuantityChange = (newQuantity: number) => {
    if (newQuantity >= 1 && newQuantity <= maxQuantity) {
      onUpdateQuantity?.(item.id, newQuantity);
    }
  };

  const handleIncrement = () => {
    if (!isMaxQuantity) {
      handleQuantityChange(item.quantity + 1);
    }
  };

  const handleDecrement = () => {
    if (!isMinQuantity) {
      handleQuantityChange(item.quantity - 1);
    }
  };

  const handleRemove = () => {
    setIsRemoving(true);
    setTimeout(() => {
      onRemove?.(item.id);
    }, 300);
  };

  const subtotal = item.price * item.quantity;

  return (
    <div
      className={`relative bg-white rounded-xl shadow-sm border border-gray-200 p-4 md:p-6 transition-all duration-300 ${
        isRemoving ? 'opacity-50 translate-x-full' : 'opacity-100'
      } ${isLoading ? 'animate-pulse' : ''}`}
    >
      <div className="flex flex-col md:flex-row gap-4 md:gap-6">
        {/* Checkbox (if selectable) */}
        {onToggleSelect && !readOnly && (
          <div className="flex items-center">
            <label className="flex items-center cursor-pointer">
              <input
                type="checkbox"
                checked={item.selected ?? false}
                onChange={(e) => onToggleSelect(item.id, e.target.checked)}
                className="w-5 h-5 text-blue-600 border-gray-300 rounded focus:ring-blue-500 cursor-pointer"
              />
            </label>
          </div>
        )}

        {/* Product Image */}
        <div className="flex-shrink-0">
          <div className="w-24 h-24 md:w-32 md:h-32 rounded-lg overflow-hidden bg-gray-100 relative">
            {!imageLoaded && !imageError && (
              <div className="absolute inset-0 bg-gray-200 animate-pulse" />
            )}
            {imageError ? (
              <div className="absolute inset-0 flex items-center justify-center bg-gray-200">
                <svg
                  className="w-8 h-8 text-gray-400"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"
                  />
                </svg>
              </div>
            ) : (
              <img
                src={item.image}
                alt={item.name}
                className={`w-full h-full object-cover transition-opacity ${
                  imageLoaded ? 'opacity-100' : 'opacity-0'
                }`}
                onLoad={() => setImageLoaded(true)}
                onError={() => setImageError(true)}
              />
            )}
          </div>
        </div>

        {/* Product Details */}
        <div className="flex-1 min-w-0">
          <div className="flex flex-col md:flex-row md:justify-between gap-4">
            <div className="flex-1">
              <h3 className="text-lg font-semibold text-gray-800 mb-1">
                {item.name}
              </h3>
              <p className="text-gray-500 text-sm mb-3">
                Unit Price: ${item.price.toFixed(2)}
              </p>

              {/* Quantity Controls */}
              {!readOnly && (
                <div className="flex items-center gap-3">
                  <div className="flex items-center border border-gray-300 rounded-lg">
                    <button
                      onClick={handleDecrement}
                      disabled={isMinQuantity || isLoading}
                      className={`px-3 py-2 text-gray-600 hover:bg-gray-100 transition-colors rounded-l-lg ${
                        isMinQuantity || isLoading
                          ? 'opacity-50 cursor-not-allowed'
                          : ''
                      }`}
                      aria-label="Decrease quantity"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4" />
                      </svg>
                    </button>
                    <input
                      type="number"
                      value={item.quantity}
                      onChange={(e) => {
                        const value = parseInt(e.target.value);
                        if (!isNaN(value)) {
                          handleQuantityChange(value);
                        }
                      }}
                      min={1}
                      max={maxQuantity}
                      className="w-12 text-center border-x border-gray-300 py-2 focus:outline-none focus:ring-0"
                      aria-label="Quantity"
                    />
                    <button
                      onClick={handleIncrement}
                      disabled={isMaxQuantity || isLoading}
                      className={`px-3 py-2 text-gray-600 hover:bg-gray-100 transition-colors rounded-r-lg ${
                        isMaxQuantity || isLoading
                          ? 'opacity-50 cursor-not-allowed'
                          : ''
                      }`}
                      aria-label="Increase quantity"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                      </svg>
                    </button>
                  </div>

                  {maxQuantity <= 5 && (
                    <span className="text-xs text-orange-500">
                      Max: {maxQuantity}
                    </span>
                  )}
                </div>
              )}

              {/* Read-only quantity display */}
              {readOnly && (
                <p className="text-gray-600">
                  Quantity: <span className="font-medium">{item.quantity}</span>
                </p>
              )}
            </div>

            {/* Price & Actions */}
            <div className="flex md:flex-col items-start md:items-end justify-between md:justify-start gap-2">
              <div className="text-right">
                <p className="text-xl font-bold text-gray-900">
                  ${subtotal.toFixed(2)}
                </p>
                {item.quantity > 1 && (
                  <p className="text-sm text-gray-500">
                    ${item.price.toFixed(2)} × {item.quantity}
                  </p>
                )}
              </div>

              {/* Action Buttons */}
              {!readOnly && (
                <div className="flex items-center gap-2">
                  {onSaveForLater && (
                    <button
                      onClick={() => onSaveForLater(item)}
                      className="text-sm text-blue-600 hover:text-blue-700 hover:underline"
                    >
                      Save for later
                    </button>
                  )}
                  <button
                    onClick={handleRemove}
                    disabled={isLoading}
                    className="text-sm text-red-500 hover:text-red-600 hover:underline disabled:opacity-50"
                    aria-label="Remove item"
                  >
                    Remove
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Loading Overlay */}
      {isLoading && (
        <div className="absolute inset-0 bg-white/50 rounded-xl flex items-center justify-center">
          <div className="w-6 h-6 border-2 border-blue-600 border-t-transparent rounded-full animate-spin" />
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';

export interface OrderItem {
  productId: string | number;
  name: string;
  price: number;
  quantity: number;
  image: string;
}

export type OrderStatus = 
  | 'pending'
  | 'processing'
  | 'shipped'
  | 'delivered'
  | 'cancelled'
  | 'refunded';

export interface Order {
  id: string | number;
  orderNumber: string;
  items: OrderItem[];
  totalAmount: number;
  status: OrderStatus;
  createdAt: string;
  updatedAt: string;
  shippingAddress?: {
    fullName: string;
    street: string;
    city: string;
    state: string;
    zipCode: string;
    country: string;
  };
  paymentMethod?: string;
  trackingNumber?: string;
  estimatedDelivery?: string;
}

interface OrderCardProps {
  order: Order;
  onViewDetails?: (order: Order) => void;
  onCancel?: (orderId: string | number) => void;
  onReorder?: (order: Order) => void;
  onTrack?: (order: Order) => void;
  isLoading?: boolean;
}

export default function OrderCard({
  order,
  onViewDetails,
  onCancel,
  onReorder,
  onTrack,
  isLoading = false,
}: OrderCardProps) {
  const [isExpanded, setIsExpanded] = useState(false);
  const [imageErrors, setImageErrors] = useState<Record<number, boolean>>({});

  const statusConfig: Record<OrderStatus, { label: string; color: string; bgColor: string }> = {
    pending: {
      label: 'Pending',
      color: 'text-yellow-600',
      bgColor: 'bg-yellow-100',
    },
    processing: {
      label: 'Processing',
      color: 'text-blue-600',
      bgColor: 'bg-blue-100',
    },
    shipped: {
      label: 'Shipped',
      color: 'text-purple-600',
      bgColor: 'bg-purple-100',
    },
    delivered: {
      label: 'Delivered',
      color: 'text-green-600',
      bgColor: 'bg-green-100',
    },
    cancelled: {
      label: 'Cancelled',
      color: 'text-red-600',
      bgColor: 'bg-red-100',
    },
    refunded: {
      label: 'Refunded',
      color: 'text-gray-600',
      bgColor: 'bg-gray-100',
    },
  };

  const status = statusConfig[order.status];

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    });
  };

  const handleImageError = (index: number) => {
    setImageErrors((prev) => ({ ...prev, [index]: true }));
  };

  const canCancel = order.status === 'pending' || order.status === 'processing';
  const canTrack = order.status === 'shipped';

  return (
    <div
      className={`bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden transition-all duration-300 ${
        isLoading ? 'animate-pulse' : ''
      }`}
    >
      {/* Order Header */}
      <div className="p-4 md:p-6 border-b border-gray-200">
        <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
          <div className="flex flex-col md:flex-row md:items-center gap-4 md:gap-6">
            {/* Order Number */}
            <div>
              <p className="text-xs text-gray-500 uppercase tracking-wide">
                Order Number
              </p>
              <p className="text-lg font-semibold text-gray-800">
                {order.orderNumber}
              </p>
            </div>

            {/* Order Date */}
            <div>
              <p className="text-xs text-gray-500 uppercase tracking-wide">
                Order Date
              </p>
              <p className="text-gray-700">{formatDate(order.createdAt)}</p>
            </div>

            {/* Status Badge */}
            <span
              className={`inline-flex items-center px-3 py-1 rounded-full text-sm font-medium ${status.color} ${status.bgColor}`}
            >
              {order.status === 'shipped' && (
                <svg
                  className="w-4 h-4 mr-1 animate-pulse"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M13 16V6a1 1 0 00-1-1H4a1 1 0 00-1 1v10a1 1 0 001 1h1m8-1a1 1 0 01-1 1H9m4-1V8a1 1 0 011-1h2.586a1 1 0 01.707.293l3.414 3.414a1 1 0 01.293.707V16a1 1 0 01-1 1h-1m-6-1a1 1 0 001 1h1M5 17a2 2 0 104 0m-4 0a2 2 0 114 0m6 0a2 2 0 104 0m-4 0a2 2 0 114 0"
                  />
                </svg>
              )}
              {status.label}
            </span>
          </div>

          {/* Total Amount */}
          <div className="text-left md:text-right">
            <p className="text-xs text-gray-500 uppercase tracking-wide">
              Total
            </p>
            <p className="text-2xl font-bold text-gray-900">
              ${order.totalAmount.toFixed(2)}
            </p>
          </div>
        </div>

        {/* Tracking Number (if available) */}
        {order.trackingNumber && (
          <div className="mt-4 p-3 bg-gray-50 rounded-lg">
            <p className="text-sm text-gray-600">
              <span className="font-medium">Tracking Number:</span>{' '}
              <span className="font-mono text-blue-600">
                {order.trackingNumber}
              </span>
            </p>
          </div>
        )}

        {/* Estimated Delivery */}
        {order.estimatedDelivery && order.status !== 'delivered' && (
          <div className="mt-3 flex items-center text-sm text-gray-600">
            <svg
              className="w-4 h-4 mr-2 text-gray-400"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"
              />
            </svg>
            Estimated delivery:{' '}
            <span className="font-medium ml-1">
              {formatDate(order.estimatedDelivery)}
            </span>
          </div>
        )}
      </div>

      {/* Order Items Preview */}
      <div className="p-4 md:p-6">
        <div className="flex items-center justify-between mb-4">
          <h4 className="text-sm font-medium text-gray-500 uppercase tracking-wide">
            Items ({order.items.length})
          </h4>
          <button
            onClick={() => setIsExpanded(!isExpanded)}
            className="text-sm text-blue-600 hover:text-blue-700 font-medium flex items-center"
          >
            {isExpanded ? 'Hide details' : 'Show details'}
            <svg
              className={`w-4 h-4 ml-1 transition-transform ${
                isExpanded ? 'rotate-180' : ''
              }`}
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M19 9l-7 7-7-7"
              />
            </svg>
          </button>
        </div>

        {/* Items Grid */}
        <div className="flex flex-wrap gap-3">
          {order.items.slice(0, isExpanded ? undefined : 3).map((item, index) => (
            <div
              key={`${item.productId}-${index}`}
              className="flex items-center gap-3 bg-gray-50 rounded-lg p-2"
            >
              <div className="w-16 h-16 rounded-lg overflow-hidden bg-white flex-shrink-0">
                {imageErrors[index] ? (
                  <div className="w-full h-full flex items-center justify-center bg-gray-200">
                    <svg
                      className="w-6 h-6 text-gray-400"
                      fill="none"
                      stroke="currentColor"
                      viewBox="0 0 24 24"
                    >
                      <path
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        strokeWidth={2}
                        d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"
                      />
                    </svg>
                  </div>
                ) : (
                  <img
                    src={item.image}
                    alt={item.name}
                    className="w-full h-full object-cover"
                    onError={() => handleImageError(index)}
                  />
                )}
              </div>
              <div className="min-w-0">
                <p className="text-sm font-medium text-gray-800 truncate max-w-[150px]">
                  {item.name}
                </p>
                <p className="text-xs text-gray-500">
                  Qty: {item.quantity} × ${item.price.toFixed(2)}
                </p>
              </div>
            </div>
          ))}
          {!isExpanded && order.items.length > 3 && (
            <div className="flex items-center justify-center w-16 h-16 bg-gray-100 rounded-lg">
              <span className="text-sm text-gray-500 font-medium">
                +{order.items.length - 3}
              </span>
            </div>
          )}
        </div>

        {/* Expanded Items List */}
        {isExpanded && (
          <div className="mt-4 pt-4 border-t border-gray-200">
            {order.items.map((item, index) => (
              <div
                key={`${item.productId}-${index}`}
                className="flex items-center justify-between py-3 border-b border-gray-100 last:border-b-0"
              >
                <div className="flex items-center gap-3">
                  <div className="w-12 h-12 rounded-lg overflow-hidden bg-gray-100">
                    {imageErrors[index] ? (
                      <div className="w-full h-full flex items-center justify-center bg-gray-200">
                        <svg
                          className="w-5 h-5 text-gray-400"
                          fill="none"
                          stroke="currentColor"
                          viewBox="0 0 24 24"
                        >
                          <path
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            strokeWidth={2}
                            d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"
                          />
                        </svg>
                      </div>
                    ) : (
                      <img
                        src={item.image}
                        alt={item.name}
                        className="w-full h-full object-cover"
                        onError={() => handleImageError(index)}
                      />
                    )}
                  </div>
                  <div>
                    <p className="text-sm font-medium text-gray-800">{item.name}</p>
                    <p className="text-xs text-gray-500">
                      ${item.price.toFixed(2)} × {item.quantity}
                    </p>
                  </div>
                </div>
                <p className="text-sm font-semibold text-gray-900">
                  ${(item.price * item.quantity).toFixed(2)}
                </p>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Order Actions */}
      <div className="px-4 md:px-6 py-4 bg-gray-50 border-t border-gray-200">
        <div className="flex flex-wrap gap-3 justify-end">
          {canTrack && order.trackingNumber && (
            <button
              onClick={() => onTrack?.(order)}
              className="px-4 py-2 text-purple-600 border border-purple-600 rounded-lg hover:bg-purple-50 transition-colors flex items-center gap-2"
            >
              <svg
                className="w-4 h-4"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M13 16V6a1 1 0 00-1-1H4a1 1 0 00-1 1v10a1 1 0 001 1h1m8-1a1 1 0 01-1 1H9m4-1V8a1 1 0 011-1h2.586a1 1 0 01.707.293l3.414 3.414a1 1 0 01.293.707V16a1 1 0 01-1 1h-1m-6-1a1 1 0 001 1h1M5 17a2 2 0 104 0m-4 0a2 2 0 114 0m6 0a2 2 0 104 0m-4 0a2 2 0 114 0"
                />
              </svg>
              Track Order
            </button>
          )}

          {onReorder && (
            <button
              onClick={() => onReorder(order)}
              className="px-4 py-2 text-blue-600 border border-blue-600 rounded-lg hover:bg-blue-50 transition-colors flex items-center gap-2"
            >
              <svg
                className="w-4 h-4"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"
                />
              </svg>
              Buy Again
            </button>
          )}

          {onViewDetails && (
            <button
              onClick={() => onViewDetails(order)}
              className="px-4 py-2 text-gray-600 border border-gray-300 rounded-lg hover:bg-gray-100 transition-colors flex items-center gap-2"
            >
              <svg
                className="w-4 h-4"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"
                />
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"
                />
              </svg>
              View Details
            </button>
          )}

          {canCancel && onCancel && (
            <button
              onClick={() => onCancel(order.id)}
              className="px-4 py-2 text-red-600 border border-red-600 rounded-lg hover:bg-red-50 transition-colors flex items-center gap-2"
            >
              <svg
                className="w-4 h-4"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M6 18L18 6M6 6l12 12"
                />
              </svg>
              Cancel Order
            </button>
          )}
        </div>
      </div>

      {/* Loading Overlay */}
      {isLoading && (
        <div className="absolute inset-0 bg-white/50 rounded-xl flex items-center justify-center">
          <div className="w-8 h-8 border-2 border-blue-600 border-t-transparent rounded-full animate-spin" />
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';

type LoadingVariant = 'spinner' | 'dots' | 'pulse' | 'skeleton' | 'progress';
type LoadingSize = 'sm' | 'md' | 'lg' | 'xl';

interface LoadingProps {
  variant?: LoadingVariant;
  size?: LoadingSize;
  color?: 'primary' | 'white' | 'gray';
  fullScreen?: boolean;
  text?: string;
  progress?: number; // 0-100 for progress variant
  overlay?: boolean;
  onComplete?: () => void;
}

export default function Loading({
  variant = 'spinner',
  size = 'md',
  color = 'primary',
  fullScreen = false,
  text,
  progress,
  overlay = false,
  onComplete,
}: LoadingProps) {
  const [internalProgress, setInternalProgress] = useState(0);

  useEffect(() => {
    if (variant === 'progress' && progress !== undefined && onComplete) {
      if (progress >= 100) {
        onComplete();
      }
    }
  }, [variant, progress, onComplete]);

  useEffect(() => {
    if (variant === 'progress' && progress === undefined) {
      const interval = setInterval(() => {
        setInternalProgress((prev) => {
          if (prev >= 100) {
            clearInterval(interval);
            onComplete?.();
            return 100;
          }
          return prev + 2;
        });
      }, 50);
      return () => clearInterval(interval);
    }
  }, [variant, progress, onComplete]);

  const currentProgress = progress ?? internalProgress;

  const sizeClasses: Record<LoadingSize, string> = {
    sm: 'w-4 h-4',
    md: 'w-8 h-8',
    lg: 'w-12 h-12',
    xl: 'w-16 h-16',
  };

  const colorClasses: Record<string, string> = {
    primary: 'border-blue-600 border-t-transparent',
    white: 'border-white border-t-transparent',
    gray: 'border-gray-400 border-t-transparent',
  };

  const textSizeClasses: Record<LoadingSize, string> = {
    sm: 'text-xs',
    md: 'text-sm',
    lg: 'text-base',
    xl: 'text-lg',
  };

  const renderSpinner = () => (
    <div className={`${sizeClasses[size]} border-4 rounded-full animate-spin ${colorClasses[color]}`} />
  );

  const renderDots = () => {
    const dotSizes: Record<LoadingSize, string> = {
      sm: 'w-1 h-1',
      md: 'w-2 h-2',
      lg: 'w-3 h-3',
      xl: 'w-4 h-4',
    };

    return (
      <div className="flex items-center gap-1">
        {[0, 1, 2].map((i) => (
          <div
            key={i}
            className={`${dotSizes[size]} rounded-full ${
              color === 'white' ? 'bg-white' : color === 'gray' ? 'bg-gray-400' : 'bg-blue-600'
            }`}
            style={{
              animation: `bounce 1.4s infinite ease-in-out both ${i * 0.16}s`,
            }}
          />
        ))}
      </div>
    );
  };

  const renderPulse = () => (
    <div className="relative">
      <div
        className={`${sizeClasses[size]} rounded-full ${
          color === 'white' ? 'bg-white' : color === 'gray' ? 'bg-gray-400' : 'bg-blue-600'
        } opacity-75 animate-ping`}
      />
      <div
        className={`absolute top-0 left-0 ${sizeClasses[size]} rounded-full ${
          color === 'white' ? 'bg-white' : color === 'gray' ? 'bg-gray-400' : 'bg-blue-600'
        }`}
      />
    </div>
  );

  const renderSkeleton = () => {
    const skeletonSizes: Record<LoadingSize, { box: string; text: string }> = {
      sm: { box: 'w-24 h-24', text: 'w-16 h-4' },
      md: { box: 'w-32 h-32', text: 'w-24 h-5' },
      lg: { box: 'w-48 h-48', text: 'w-32 h-6' },
      xl: { box: 'w-64 h-64', text: 'w-40 h-7' },
    };

    return (
      <div className="animate-pulse flex flex-col items-center gap-4">
        <div className={`${skeletonSizes[size].box} bg-gray-200 rounded-xl`} />
        <div className="space-y-2 w-full">
          <div className={`${skeletonSizes[size].text} bg-gray-200 rounded h-4 mx-auto`} />
          <div className={`w-3/4 h-4 bg-gray-200 rounded mx-auto`} />
        </div>
      </div>
    );
  };

  const renderProgress = () => {
    const progressSizes: Record<LoadingSize, { bar: string; text: string }> = {
      sm: { bar: 'h-1', text: 'text-xs' },
      md: { bar: 'h-2', text: 'text-sm' },
      lg: { bar: 'h-3', text: 'text-base' },
      xl: { bar: 'h-4', text: 'text-lg' },
    };

    return (
      <div className="w-full max-w-xs">
        <div className={`w-full bg-gray-200 rounded-full ${progressSizes[size].bar}`}>
          <div
            className={`rounded-full ${
              color === 'white'
                ? 'bg-white'
                : color === 'gray'
                ? 'bg-gray-400'
                : 'bg-blue-600'
            } transition-all duration-300 ease-out`}
            style={{ width: `${Math.min(100, Math.max(0, currentProgress))}%` }}
          />
        </div>
        <p className={`${progressSizes[size].text} text-gray-500 mt-2 text-center`}>
          {Math.round(currentProgress)}%
        </p>
      </div>
    );
  };

  const renderContent = () => {
    switch (variant) {
      case 'spinner':
        return renderSpinner();
      case 'dots':
        return renderDots();
      case 'pulse':
        return renderPulse();
      case 'skeleton':
        return renderSkeleton();
      case 'progress':
        return renderProgress();
      default:
        return renderSpinner();
    }
  };

  const loadingContent = (
    <div className="flex flex-col items-center justify-center gap-4">
      {renderContent()}
      {text && (
        <p className={`${textSizeClasses[size]} text-gray-600 font-medium`}>
          {text}
        </p>
      )}
    </div>
  );

  // Full Screen Loading
  if (fullScreen) {
    return (
      <div className="fixed inset-0 bg-white/80 backdrop-blur-sm flex items-center justify-center z-50">
        {loadingContent}
      </div>
    );
  }

  // Overlay Loading (centered in parent)
  if (overlay) {
    return (
      <div className="absolute inset-0 bg-white/60 backdrop-blur-sm flex items-center justify-center rounded-xl z-10">
        <div className="flex flex-col items-center justify-center gap-3">
          <div className={`${sizeClasses[size]} border-4 rounded-full animate-spin ${colorClasses[color]}`} />
          {text && (
            <p className={`${textSizeClasses[size]} text-gray-600 font-medium`}>
              {text}
            </p>
          )}
        </div>
      </div>
    );
  }

  // Simple inline loading
  return loadingContent;
}

