import {
  forwardRef,
  useState,
  useCallback,
  useEffect,
  useRef,
  useId,
  type InputHTMLAttributes,
  type ReactNode,
} from 'react';

// ============================================
// Type Definitions
// ============================================

export type InputSize = 'sm' | 'md' | 'lg';
export type InputVariant = 'outlined' | 'filled' | 'flushed';
export type InputType =
  | 'text'
  | 'email'
  | 'password'
  | 'number'
  | 'tel'
  | 'url'
  | 'search'
  | 'date'
  | 'datetime-local'
  | 'time'
  | 'month'
  | 'week'
  | 'file'
  | 'range'
  | 'color';

export interface InputProps
  extends Omit<InputHTMLAttributes<HTMLInputElement>, 'size'> {
  /** Input label */
  label?: string;
  /** Placeholder text */
  placeholder?: string;
  /** Help text below input */
  helpText?: string;
  /** Error message */
  error?: string;
  /** Success message */
  success?: string;
  /** Input size */
  size?: InputSize;
  /** Input variant style */
  variant?: InputVariant;
  /** Left icon component */
  leftIcon?: ReactNode;
  /** Right icon component */
  rightIcon?: ReactNode;
  /** Whether to show password toggle */
  showPasswordToggle?: boolean;
  /** Whether input is loading */
  loading?: boolean;
  /** Whether to show character count */
  showCharCount?: boolean;
  /** Max character length */
  maxLength?: number;
  /** Prefix text or component */
  prefix?: string | ReactNode;
  /** Suffix text or component */
  suffix?: string | ReactNode;
  /** Container class name */
  containerClassName?: string;
  /** Label class name */
  labelClassName?: string;
  /** Input wrapper class name */
  inputWrapperClassName?: string;
  /** Callback when value changes */
  onChange?: (
    e: React.ChangeEvent<HTMLInputElement>
  ) => void;
  /** Callback when input gains focus */
  onFocus?: (e: React.FocusEvent<HTMLInputElement>) => void;
  /** Callback when input loses focus */
  onBlur?: (e: React.FocusEvent<HTMLInputElement>) => void;
  /** Callback when clear button is clicked */
  onClear?: () => void;
  /** Validation function */
  validate?: (value: string) => boolean | string;
  /** Debounce timeout for validation in ms */
  debounceTimeout?: number;
}

// ============================================
// Styles Configuration
// ============================================

const sizeStyles: Record<InputSize, { input: string; icon: string; prefix: string }> = {
  sm: {
    input: 'px-3 py-1.5 text-sm',
    icon: 'w-4 h-4',
    prefix: 'px-2 py-1.5 text-sm',
  },
  md: {
    input: 'px-4 py-2.5 text-base',
    icon: 'w-5 h-5',
    prefix: 'px-3 py-2.5 text-base',
  },
  lg: {
    input: 'px-5 py-3 text-lg',
    icon: 'w-6 h-6',
    prefix: 'px-4 py-3 text-lg',
  },
};

const variantStyles = {
  outlined: {
    base: 'border bg-transparent',
    focus: 'focus:ring-2 focus:ring-blue-500 focus:border-blue-500',
    error: 'border-red-500 focus:ring-red-500 focus:border-red-500',
    success: 'border-green-500 focus:ring-green-500 focus:border-green-500',
  },
  filled: {
    base: 'border-0 bg-gray-100',
    focus: 'focus:ring-2 focus:ring-blue-500 bg-white',
    error: 'bg-red-50 focus:ring-red-500',
    success: 'bg-green-50 focus:ring-green-500',
  },
  flushed: {
    base: 'border-0 border-b bg-transparent rounded-none px-0',
    focus: 'focus:ring-0 focus:border-2 focus:border-blue-500',
    error: 'border-b-2 border-red-500',
    success: 'border-b-2 border-green-500',
  },
};

// ============================================
// Main Input Component
// ============================================

const Input = forwardRef<HTMLInputElement, InputProps>(
  (
    {
      type = 'text',
      label,
      placeholder,
      helpText,
      error,
      success,
      size = 'md',
      variant = 'outlined',
      leftIcon,
      rightIcon,
      showPasswordToggle = false,
      loading = false,
      showCharCount = false,
      maxLength,
      prefix,
      suffix,
      disabled = false,
      readOnly = false,
      required = false,
      containerClassName = '',
      labelClassName = '',
      inputWrapperClassName = '',
      onChange,
      onFocus,
      onBlur,
      onClear,
      validate,
      debounceTimeout,
      className = '',
      value,
      id: providedId,
      ...props
    },
    ref
  ) => {
    const generatedId = useId();
    const id = providedId || generatedId;
    const inputRef = useRef<HTMLInputElement>(null);

    const [showPassword, setShowPassword] = useState(false);
    const [isFocused, setIsFocused] = useState(false);
    const [internalValue, setInternalValue] = useState(value as string);
    const [validationMessage, setValidationMessage] = useState<string | null>(null);

    // Use ref for callbacks to avoid re-renders
    const debounceRef = useRef<NodeJS.Timeout>();

    // Sync internal value with prop value
    useEffect(() => {
      setInternalValue(value as string);
    }, [value]);

    // Get current input type (handle password visibility)
    const inputType =
      type === 'password' ? (showPassword ? 'text' : 'password') : type;

    // Determine variant style
    const variantClass = variantStyles[variant];
    let borderClass = variantClass.base;
    if (error) {
      borderClass = variantClass.error;
    } else if (success && !error) {
      borderClass = variantClass.success;
    }

    // Handle value change
    const handleChange = useCallback(
      (e: React.ChangeEvent<HTMLInputElement>) => {
        const newValue = e.target.value;

        // Update internal state
        setInternalValue(newValue);

        // Clear previous debounce
        if (debounceRef.current) {
          clearTimeout(debounceRef.current);
        }

        // Handle debounced validation
        if (debounceTimeout && validate) {
          debounceRef.current = setTimeout(() => {
            const result = validate(newValue);
            if (typeof result === 'string') {
              setValidationMessage(result);
            } else if (!result) {
              setValidationMessage('Invalid input');
            } else {
              setValidationMessage(null);
            }
          }, debounceTimeout);
        }

        // Call onChange
        onChange?.(e);
      },
      [onChange, debounceTimeout, validate]
    );

    // Handle focus
    const handleFocus = useCallback(
      (e: React.FocusEvent<HTMLInputElement>) => {
        setIsFocused(true);
        onFocus?.(e);
      },
      [onFocus]
    );

    // Handle blur
    const handleBlur = useCallback(
      (e: React.FocusEvent<HTMLInputElement>) => {
        setIsFocused(false);

        // Run validation on blur if provided
        if (validate) {
          const result = validate(e.target.value);
          if (typeof result === 'string') {
            setValidationMessage(result);
          } else if (!result) {
            setValidationMessage('Invalid input');
          } else {
            setValidationMessage(null);
          }
        }

        onBlur?.(e);
      },
      [onBlur, validate]
    );

    // Handle clear
    const handleClear = useCallback(() => {
      setInternalValue('');
      onClear?.();
      inputRef.current?.focus();
    }, [onClear]);

    // Toggle password visibility
    const togglePassword = useCallback(() => {
      setShowPassword((prev) => !prev);
    }, []);

    // Focus input when clicking label
    const handleLabelClick = useCallback(() => {
      inputRef.current?.focus();
    }, []);

    // Get current validation message
    const displayError = error || validationMessage;

    // Calculate character count
    const currentLength = typeof internalValue === 'string' ? internalValue.length : 0;
    const charCountText = maxLength ? `${currentLength}/${maxLength}` : currentLength;

    // Check if input is valid
    const isValid = !displayError && success && internalValue;

    return (
      <div className={`w-full ${containerClassName}`}>
        {/* Label */}
        {label && (
          <label
            htmlFor={id}
            onClick={handleLabelClick}
            className={`block text-sm font-medium text-gray-700 mb-1.5 cursor-pointer ${labelClassName} ${
              required ? "after:content-['*'] after:ml-1 after:text-red-500" : ''
            }`}
          >
            {label}
          </label>
        )}

        {/* Input Wrapper */}
        <div
          className={`relative rounded-lg ${inputWrapperClassName} ${
            variant === 'flushed' ? '' : 'overflow-hidden'
          }`}
        >
          {/* Prefix */}
          {prefix && (
            <div
              className={`absolute inset-y-0 left-0 flex items-center pointer-events-none text-gray-500 ${sizeStyles[size].prefix}`}
            >
              {prefix}
            </div>
          )}

          {/* Left Icon */}
          {leftIcon && (
            <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
              <span className={sizeStyles[size].icon}>{leftIcon}</span>
            </div>
          )}

          {/* Input Element */}
          <input
            ref={(node) => {
              // Handle both refs
              (inputRef as React.MutableRefObject<HTMLInputElement | null>).current = node;
              if (typeof ref === 'function') {
                ref(node);
              } else if (ref) {
                ref.current = node;
              }
            }}
            id={id}
            type={inputType}
            value={internalValue}
            onChange={handleChange}
            onFocus={handleFocus}
            onBlur={handleBlur}
            placeholder={placeholder}
            disabled={disabled || loading}
            readOnly={readOnly}
            required={required}
            maxLength={maxLength}
            className={`
              block w-full rounded-lg transition-all duration-200
              text-gray-900 placeholder-gray-400
              disabled:bg-gray-100 disabled:cursor-not-allowed disabled:opacity-60
              ${borderClass}
              ${variantClass.base.includes('focus') ? variantClass.focus : ''}
              ${sizeStyles[size].input}
              ${leftIcon || prefix ? 'pl-10' : ''}
              ${rightIcon || showPasswordToggle || suffix || isValid || loading ? 'pr-10' : ''}
              ${className}
            `}
            aria-invalid={!!displayError}
            aria-describedby={
              displayError
                ? `${id}-error`
                : helpText
                ? `${id}-help`
                : undefined
            }
            {...props}
          />

          {/* Right Icon Container */}
          {(rightIcon || showPasswordToggle || suffix || loading || isValid || (onClear && internalValue)) && (
            <div className="absolute inset-y-0 right-0 flex items-center pr-3 gap-2">
              {/* Clear Button */}
              {onClear && internalValue && !loading && (
                <button
                  type="button"
                  onClick={handleClear}
                  className="text-gray-400 hover:text-gray-600 focus:outline-none"
                  aria-label="Clear input"
                >
                  <svg className={sizeStyles[size].icon} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              )}

              {/* Success Icon */}
              {isValid && !loading && (
                <svg className={`${sizeStyles[size].icon} text-green-500`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                </svg>
              )}

              {/* Loading Spinner */}
              {loading && (
                <svg className={`${sizeStyles[size].icon} animate-spin text-gray-400`} fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                </svg>
              )}

              {/* Password Toggle */}
              {showPasswordToggle && type === 'password' && (
                <button
                  type="button"
                  onClick={togglePassword}
                  className="text-gray-400 hover:text-gray-600 focus:outline-none"
                  aria-label={showPassword ? 'Hide password' : 'Show password'}
                >
                  {showPassword ? (
                    <svg className={sizeStyles[size].icon} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21" />
                    </svg>
                  ) : (
                    <svg className={sizeStyles[size].icon} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                    </svg>
                  )}
                </button>
              )}

              {/* Suffix */}
              {suffix && !loading && !isValid && (
                <span className="text-gray-500">{suffix}</span>
              )}
            </div>
          )}

          {/* Character Count */}
          {showCharCount && maxLength && (
            <div
              className={`absolute -bottom-5 right-0 text-xs ${
                currentLength >= maxLength ? 'text-red-500' : 'text-gray-400'
              }`}
            >
              {charCountText}
            </div>
          )}
        </div>

        {/* Help Text */}
        {helpText && !displayError && (
          <p id={`${id}-help`} className="mt-1.5 text-sm text-gray-500">
            {helpText}
          </p>
        )}

        {/* Error Message */}
        {displayError && (
          <p
            id={`${id}-error`}
            className="mt-1.5 text-sm text-red-600 flex items-center gap-1"
            role="alert"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            {displayError}
          </p>
        )}

        {/* Success Message */}
        {success && !displayError && (
          <p className="mt-1.5 text-sm text-green-600 flex items-center gap-1">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            {success}
          </p>
        )}
      </div>
    );
  }
);

Input.displayName = 'Input';

// ============================================
// Textarea Component
// ============================================

export interface TextareaProps
  extends React.TextareaHTMLAttributes<HTMLTextAreaElement> {
  label?: string;
  helpText?: string;
  error?: string;
  success?: string;
  showCharCount?: boolean;
  autoResize?: boolean;
  minRows?: number;
  maxRows?: number;
}

export const Textarea = forwardRef<HTMLTextAreaElement, TextareaProps>(
  (
    {
      label,
      helpText,
      error,
      success,
      showCharCount = false,
      autoResize = false,
      minRows = 3,
      maxRows = 10,
      maxLength,
      disabled = false,
      readOnly = false,
      required = false,
      className = '',
      value,
      onChange,
      ...props
    },
    ref
  ) => {
    const generatedId = useId();
    const textareaRef = useRef<HTMLTextAreaElement>(null);
    const id = props.id || generatedId;

    const [internalValue, setInternalValue] = useState(value as string);

    useEffect(() => {
      setInternalValue(value as string);
    }, [value]);

    const handleChange = useCallback(
      (e: React.ChangeEvent<HTMLTextAreaElement>) => {
        const newValue = e.target.value;
        setInternalValue(newValue);

        if (autoResize && textareaRef.current) {
          textareaRef.current.style.height = 'auto';
          const newHeight = Math.min(
            textareaRef.current.scrollHeight,
            textareaRef.current.clientHeight + maxRows * 24
          );
          textareaRef.current.style.height = `${newHeight}px`;
        }

        onChange?.(e);
      },
      [onChange, autoResize, maxRows]
    );

    const currentLength = typeof internalValue === 'string' ? internalValue.length : 0;

    return (
      <div className="w-full">
        {label && (
          <label
            htmlFor={id}
            className={`block text-sm font-medium text-gray-700 mb-1.5 ${
              required ? "after:content-['*'] after:ml-1 after:text-red-500" : ''
            }`}
          >
            {label}
          </label>
        )}

        <textarea
          ref={(node) => {
            (textareaRef as React.MutableRefObject<HTMLTextAreaElement | null>).current = node;
            if (typeof ref === 'function') {
              ref(node);
            } else if (ref) {
              ref.current = node;
            }
          }}
          id={id}
          value={internalValue}
          onChange={handleChange}
          disabled={disabled}
          readOnly={readOnly}
          required={required}
          maxLength={maxLength}
          rows={minRows}
          className={`
            block w-full px-4 py-2.5 rounded-lg border transition-all duration-200
            text-gray-900 placeholder-gray-400 resize-y
            disabled:bg-gray-100 disabled:cursor-not-allowed disabled:opacity-60
            focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500
            ${error ? 'border-red-500 focus:ring-red-500 focus:border-red-500' : ''}
            ${success && !error ? 'border-green-500 focus:ring-green-500 focus:border-green-500' : ''}
            ${className}
          `}
          aria-invalid={!!error}
          aria-describedby={
            error ? `${id}-error` : helpText ? `${id}-help` : undefined
          }
          {...props}
        />

        <div className="flex justify-between mt-1.5">
          <div>
            {helpText && !error && (
              <p id={`${id}-help`} className="text-sm text-gray-500">
                {helpText}
              </p>
            )}
            {error && (
              <p id={`${id}-error`} className="text-sm text-red-600 flex items-center gap-1" role="alert">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
                {error}
              </p>
            )}
            {success && !error && (
              <p className="text-sm text-green-600 flex items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
                {success}
              </p>
            )}
          </div>
          {showCharCount && maxLength && (
            <p className={`text-xs ${currentLength >= maxLength ? 'text-red-500' : 'text-gray-400'}`}>
              {currentLength}/{maxLength}
            </p>
          )}
        </div>
      </div>
    );
  }
);

Textarea.displayName = 'Textarea';

